/**
 * Test image fixtures for E2E tests
 * Small 1x1 pixel images in various formats for testing uploads
 */

// 1x1 pixel PNG (base64)
export const TEST_PNG_1X1 =
  "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==";

// 1x1 pixel JPEG (base64)
export const TEST_JPEG_1X1 =
  "data:image/jpeg;base64,";

// Convert data URL to File object for file input testing
export function dataUrlToFile(dataUrl: string, filename: string): File {
  const arr = dataUrl.split(",");
  const mime = arr[0].match(/:(.*?);/)?.[1] || "image/png";
  const bstr = atob(arr[1]);
  let n = bstr.length;
  const u8arr = new Uint8Array(n);
  while (n--) {
    u8arr[n] = bstr.charCodeAt(n);
  }
  return new File([u8arr], filename, { type: mime });
}
